   135|.chip-blue{border-color:rgba(59,130,246,0.2);background:rgba(59,130,246,0.05);color:#3b82f6}
   136|.chip-green{border-color:rgba(16,185,129,0.2);background:rgba(16,185,129,0.05);color:#10b981}
