   162|/* ── Timeline (story) ── */
   163|.timeline{margin-top:3rem;display:flex;flex-direction:column;gap:0;max-width:700px;margin-left:auto;margin-right:auto}
   164|.timeline-row{display:flex;gap:1.5rem;align-items:flex-start}
   165|.timeline-track{display:flex;flex-direction:column;align-items:center;flex-shrink:0}
